import sys
from collections import deque
from typing import List

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def boundaryOfBinaryTree(self, root: TreeNode) -> List[int]:
        if not root:
            return []
        result = [root.val]
        current = root.left
        while current and current.left or current.right:
            result.append(current.val)
            if current.left:
                current = current.left
            else:
                current = current.right
        self.addLeaves(root, result)
        current = root.right
        temp = []
        while current and current.left or current.right:
            temp.append(current.val)
            if current.right:
                current = current.right
            else:
                current = current.left
        result.extend(reversed(temp))
        return result

    def addLeaves(self, node, result):
        if not node:
            return
        if not node.left and not node.right:
            result.append(node.val)
            return
        self.addLeaves(node.left, result)
        self.addLeaves(node.right, result)

if __name__ == '__main__':
    n = int(sys.stdin.readline().strip())
    nodes = list(map(int, sys.stdin.readline().strip().split()))
    if n == 0:
        sys.exit(0)
    root = TreeNode(nodes[0])
    queue = deque([root])
    i = 1
    while i < n:
        current = queue.popleft()
        if nodes[i] != -1:
            current.left = TreeNode(nodes[i])
            queue.append(current.left)
        i += 1
        if i < n and nodes[i] != -1:
            current.right = TreeNode(nodes[i])
            queue.append(current.right)
        i += 1
    sol = Solution()
    ans = sol.boundaryOfBinaryTree(root)
    print(' '.join(map(str, ans)))

